#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=5005;
unordered_map<int,int> mp;
ll n,q,a[N],dp[N][N];
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n>>q;
	for(int i=1;i<=n;i++) cin>>a[i];
	for(int i=n;i>0;i--)
	{
		mp.clear();
		for(int j=i+1;j<=n;j++)
		{
			dp[i][j]=mp[-a[i]-a[j]]+dp[i+1][j]+dp[i][j-1]-dp[i+1][j-1];
			mp[a[j]]++;
		}
	}
	while(q--)
	{
		int l,r;
		cin>>l>>r;
		cout<<dp[l][r]<<"\n";
	}
	return 0;
}
